#ifndef STRIKERSRECOMP_HOST_SDK_MAP_H
#define STRIKERSRECOMP_HOST_SDK_MAP_H

#include "core/types.h"

// One entry of the SDK intercept table: a guest function address and the name
// of the GameCube SDK function that lives there. Generated by tools/symbols.py
// from the decomp symbol map crossed with Aurora's headers.
typedef struct {
    u32         address;
    const char* name;
} SdkSymbol;

// Name of the SDK function at `address`, or NULL if `address` is not an
// intercept candidate (i.e. ordinary recompiled game code). Backed by the
// generated table via binary search.
const char* sdk_symbol_name(u32 address);

// Guest address of `name`, or zero if it is not present in the generated SDK
// intercept table. Intended for building a fast client-side dispatch table at
// startup rather than doing name matching on every recompiled block.
u32 sdk_symbol_address(const char* name);

// Number of entries in the generated intercept table.
unsigned sdk_symbol_count(void);

#endif // STRIKERSRECOMP_HOST_SDK_MAP_H
